const game = items[0].json;
const mention = '{{mentionRole}}' ? `<@&{{mentionRole}}>` : '';

return [{
  json: {
    content: mention,
    embeds: [{
      title: ':game_die: New Game Added',
      description: `**${game.gameName}** has been uploaded to MeepleAI`,
      color: 5793266,
      fields: [
        { name: 'Game ID', value: game.gameId, inline: true },
        { name: 'Pages', value: String(game.pageCount), inline: true },
        { name: 'Uploaded By', value: game.uploaderName, inline: true }
      ],
      timestamp: new Date().toISOString()
    }]
  }
}];
